type CustomMapping = Record<string, string | Partial<LocaleProperties>>;

type LocaleProperties = {
    code: string;
    name: string;
    nativeName: string;
    languageCode: string;
    languageName: string;
    nativeLanguageName: string;
    nameWithRegionCode: string;
    nativeNameWithRegionCode: string;
    regionCode: string;
    regionName: string;
    nativeRegionName: string;
    scriptCode: string;
    scriptName: string;
    nativeScriptName: string;
    maximizedCode: string;
    maximizedName: string;
    nativeMaximizedName: string;
    minimizedCode: string;
    minimizedName: string;
    nativeMinimizedName: string;
    emoji: string;
};

type VariableType = 'v' | 'n' | 'd' | 'c';
/**
 * Variables are used to store the variable name and type.
 */
type Variable = {
    k: string;
    i?: number;
    v?: VariableType;
};

/**
 * Map of data-_gt properties to their corresponding React props
 */
declare const HTML_CONTENT_PROPS: {
    readonly pl: "placeholder";
    readonly ti: "title";
    readonly alt: "alt";
    readonly arl: "aria-label";
    readonly arb: "aria-labelledby";
    readonly ard: "aria-describedby";
};
type HtmlContentPropKeysRecord = Partial<Record<keyof typeof HTML_CONTENT_PROPS, string>>;
/**
 * GTProp is an internal property used to contain data for translating and rendering elements.
 * note, transformations are only read on the server side if they are 'plural' or 'branch'
 */
type GTProp = {
    b?: Record<string, JsxChildren>;
    t?: 'p' | 'b';
} & HtmlContentPropKeysRecord;
type JsxElement = {
    t?: string;
    i?: number;
    d?: GTProp;
    c?: JsxChildren;
};
type JsxChild = string | JsxElement | Variable;
/**
 * The format of the content
 */
type DataFormat = 'JSX' | 'ICU' | 'I18NEXT';
/**
 * A content type representing JSX, ICU, and I18next messages
 */
type Content = JsxChildren | IcuMessage | I18nextMessage;
/**
 * A content type representing JSX elements
 */
type JsxChildren = JsxChild | JsxChild[];
/**
 * A content type representing ICU messages
 */
type IcuMessage = string;
/**
 * A content type representing I18next messages
 */
type I18nextMessage = string;

/**
 * ActionType is the type of action to perform on the request.
 *
 * @param standard - The standard action type (standard model).
 * @param fast - The fast action type (mini model).
 * @param string - Other model
 */
type ActionType = 'standard' | 'fast' | string;
/**
 * EntryMetadata is the metadata for a GTRequest.
 *
 * @param context - The context of the request.
 * @param id - The id of the request.
 * @param maxChars - The maxChars of the request.
 * @param hash - The hash of the request.
 */
type EntryMetadata = {
    context?: string;
    id?: string;
    maxChars?: number;
    hash?: string;
    dataFormat?: DataFormat;
    sourceLocale?: string;
    actionType?: ActionType;
    timeout?: number;
    regionCode?: string;
    scriptCode?: string;
};
/**
 * GTRequest is a translation request object for {@link JsxChildren} | {@link IcuMessage} | {@link I18nextMessage}
 *
 * @param source - The source content to translate.
 * @param targetLocale - The target locale to translate to.
 * @param metadata - The metadata for the request.
 */
type Entry = {
    source: Content;
    targetLocale?: string;
    metadata?: EntryMetadata;
};

type CheckFileTranslationsOptions = {
    timeout?: number;
};
type FileQuery = {
    fileId: string;
    branchId?: string;
    versionId?: string;
};
type FileQueryResult = {
    sourceFile: {
        id: string;
        fileId: string;
        versionId: string;
        sourceLocale: string;
        fileName: string;
        fileFormat: string;
        dataFormat: string | null;
        createdAt: string;
        updatedAt: string;
        approvalRequiredAt: string | null;
        locales: string[];
    };
    translations: {
        locale: string;
        completedAt: string | null;
        approvedAt: string | null;
        publishedAt: string | null;
        createdAt: string | null;
        updatedAt: string | null;
    }[];
};

type FileFormat = 'GTJSON' | 'JSON' | 'YAML' | 'MDX' | 'MD' | 'TS' | 'JS' | 'HTML' | 'TXT';
/**
 * File object structure for referencing files
 * @param fileId - The ID of the file
 * @param versionId - The ID of the version of the file
 * @param branchId - The ID of the branch of the file
 * @param locale - The locale of the file ()
 */
type FileReference = {
    fileId: string;
    versionId: string;
    branchId: string;
    fileName: string;
    fileFormat: FileFormat;
    dataFormat?: DataFormat;
};

type DownloadFileBatchRequest = {
    fileId: string;
    branchId?: string;
    versionId?: string;
    locale?: string;
}[];
type DownloadFileBatchOptions = {
    timeout?: number;
};
type DownloadedFile = {
    id: string;
    branchId: string;
    fileId: string;
    versionId: string;
    locale?: string;
    fileName?: string;
    data: string;
    metadata: Record<string, any>;
    fileFormat: FileFormat;
};
type DownloadFileBatchResult = {
    files: DownloadedFile[];
    count: number;
};

type EnqueueFilesResult = {
    jobData: {
        [jobId: string]: {
            sourceFileId: string;
            fileId: string;
            versionId: string;
            branchId: string;
            targetLocale: string;
            projectId: string;
            force: boolean;
            modelProvider?: string;
        };
    };
    locales: string[];
    message: string;
};

/**
 * Metadata stored alongside GTJSON file entries.
 * Keys correspond to the entry id/hash in the GTJSON body.
 */
type GTJsonFormatMetadata = Record<string, {
    context?: string;
    id?: string;
    domain?: string;
    maxChars?: number;
    dataFormat?: 'JSX' | 'ICU';
    requestVersion?: number;
    approved_at?: string | null;
    approved_by?: string | null;
    hash?: string;
    filePaths?: string[];
}>;
type FileUpload = {
    branchId?: string;
    incomingBranchId?: string;
    checkedOutBranchId?: string;
    content: string;
    fileName: string;
    fileFormat: FileFormat;
    dataFormat?: DataFormat;
    locale: string;
    formatMetadata?: GTJsonFormatMetadata;
    versionId?: string;
    fileId?: string;
};
type UploadFilesOptions = {
    sourceLocale: string;
    modelProvider?: string;
    timeout?: number;
};
type UploadFilesResponse = {
    uploadedFiles: FileReference[];
    count: number;
    message: string;
};

type DownloadFileOptions = {
    timeout?: number;
};

/**
 * TranslationResultReference is used to store the reference for a translation result.
 */
type TranslationResultReference = {
    id?: string;
    hash: string;
};
/**
 * TypedResult is a union type that represents the different types of translations that can be returned.
 */
type TypedResult = {
    translation: JsxChildren;
    dataFormat: 'JSX';
} | {
    translation: I18nextMessage | IcuMessage;
    dataFormat: 'ICU' | 'I18NEXT';
};
/**
 * RequestError is a type that represents an error that occurred during a translation request.
 */
type TranslationError = {
    error: string;
    code: number;
    reference?: TranslationResultReference;
};
/**
 * RequestSuccess is a type that represents a successful translation request.
 */
type RequestSuccess = TypedResult & {
    locale: string;
    reference: TranslationResultReference;
};
type TranslationResult = RequestSuccess | TranslationError;

/**
 * BatchTranslationResult is the result of a batch translation request.
 */
type TranslateManyResult = Array<TranslationResult>;

type BranchDataResult = {
    branches: {
        id: string;
        name: string;
    }[];
    defaultBranch: {
        id: string;
        name: string;
    } | null;
};

type BranchQuery = {
    branchNames: string[];
};

type FileDataQuery = {
    sourceFiles?: {
        fileId: string;
        versionId: string;
        branchId: string;
    }[];
    translatedFiles?: {
        fileId: string;
        versionId: string;
        branchId: string;
        locale: string;
    }[];
};
type FileDataResult = {
    sourceFiles?: {
        branchId: string;
        fileId: string;
        versionId: string;
        fileName: string;
        fileFormat: string;
        dataFormat: string | null;
        createdAt: string;
        updatedAt: string;
        approvalRequiredAt: string | null;
        publishedAt: string | null;
        locales: string[];
        sourceLocale: string;
    }[];
    translatedFiles?: {
        branchId: string;
        fileId: string;
        versionId: string;
        fileFormat: string;
        dataFormat: string | null;
        createdAt: string;
        updatedAt: string;
        approvedAt: string | null;
        publishedAt: string | null;
        completedAt: string | null;
        locale: string;
    }[];
};

type JobStatus = 'queued' | 'processing' | 'completed' | 'failed' | 'unknown';
type CheckJobStatusResult = {
    jobId: string;
    status: JobStatus;
    error?: {
        message: string;
    };
}[];

type SubmitUserEditDiff = {
    fileName: string;
    locale: string;
    diff: string;
    branchId: string;
    versionId: string;
    fileId: string;
    localContent: string;
};
type SubmitUserEditDiffsPayload = {
    diffs: SubmitUserEditDiff[];
};

type FormatVariables = Record<string, string | number | boolean | null | undefined | Date>;

type SetupProjectResult = {
    setupJobId: string;
    status: 'queued';
} | {
    status: 'completed';
};
type SetupProjectOptions = {
    force?: boolean;
    locales?: string[];
    timeoutMs?: number;
};

type EnqueueOptions = {
    sourceLocale: string;
    targetLocales: string[];
    publish?: boolean;
    requireApproval?: boolean;
    modelProvider?: string;
    force?: boolean;
    timeout?: number;
};

type CustomRegionMapping = {
    [region: string]: {
        name?: string;
        emoji?: string;
        locale?: string;
    };
};

type ProjectData = {
    id: string;
    name: string;
    orgId: string;
    defaultLocale: string;
    currentLocales: string[];
};

type CreateBranchQuery = {
    branchName: string;
    defaultBranch: boolean;
};
type CreateBranchResult = {
    branch: {
        id: string;
        name: string;
    };
};

/** Type of terminator */
type CutoffFormatStyle = 'none' | 'ellipsis';
/** Terminator options */
interface TerminatorOptions {
    /** The terminator to use */
    terminator?: string;
    /** An optional separator between the terminator and the value */
    separator?: string;
}
/** Input formatting options (for constructor) */
interface CutoffFormatOptions extends TerminatorOptions {
    /** Cutoff length */
    maxChars?: number;
    /** Type of terminator */
    style?: CutoffFormatStyle;
}

/**
 * Type representing the constructor parameters for the GT class.
 * @typedef {Object} GTConstructorParams
 * @property {string} [apiKey] - The API key for accessing the translation service
 * @property {string} [devApiKey] - The development API key for accessing the translation service
 * @property {string} [sourceLocale] - The default source locale for translations
 * @property {string} [targetLocale] - The default target locale for translations
 * @property {string[]} [locales] - Array of supported locales
 * @property {string} [projectId] - The project ID for the translation service
 * @property {string} [baseUrl] - The base URL for the translation service
 * @property {CustomMapping} [customMapping] - Custom mapping of locale codes to their names
 */
type GTConstructorParams = {
    apiKey?: string;
    devApiKey?: string;
    sourceLocale?: string;
    targetLocale?: string;
    locales?: string[];
    projectId?: string;
    baseUrl?: string;
    customMapping?: CustomMapping;
};
